using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: inline DataRow for simple cases ---

    [TestMethod]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "Basic with 10% tax")]
    [DataRow(5.50, 4, 0.0, 22.00, DisplayName = "Zero tax")]
    [DataRow(0.00, 5, 0.25, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 1, 0.08, 107.9892, DisplayName = "Single item with 8% tax")]
    [DataRow(25.00, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for boundary/edge cases ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalBoundaryData))]
    public void CalculateTotal_BoundaryCases_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalBoundaryData =>
    [
        (0.01m, 1, 0m, 0.01m),       // Minimum meaningful price
        (1000m, 100, 1m, 200000m),    // Tax rate at max (100%)
        (9999.99m, 1, 0.5m, 14999.985m), // High price, 50% tax
    ];

    // --- CalculateTotal: invalid input throws ---

    [TestMethod]
    [DataRow(-1.00, 2, 0.10, "unitPrice", DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity")]
    public void CalculateTotal_InvalidInput_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidPercent_ReturnsDiscountedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 0m, 100m),       // No discount
        (100m, 10m, 90m),       // 10% off
        (200m, 25m, 150m),      // 25% off
        (50m, 50m, 25m),        // Half price
        (80m, 100m, 0m),        // Full discount
        (33.33m, 15m, 28.3305m), // Fractional result
    ];

    // --- ApplyDiscount: invalid discount throws ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0%")]
    [DataRow(100.01, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice: DataRow ---

    [TestMethod]
    [DataRow(9.99, "$", "$9.99", DisplayName = "Default currency")]
    [DataRow(1234.5, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.0, "£", "£0.00", DisplayName = "Zero with pounds")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

